import React from 'react';
import { Link } from 'react-router-dom';

function Home() {
  return (
    <div className="text-center py-5 text-white" style={{ background: 'linear-gradient(45deg, #0f2027, #2c5364)', minHeight: '80vh' }}>
      <h1 className="display-4 fw-bold mt-5">Hi, I'm a Freelancer</h1>
      <p className="lead">मी तुमच्या व्यवसायासाठी उत्तम डिजिटल सोल्यूशन्स देतो.</p>
      <Link to="/services" className="btn btn-primary btn-lg mt-3">माझ्या सर्व्हिसेस पहा</Link>
    </div>
  );
}
export default Home;
